// Extract existing booking data from sheet lookup result
// This node runs right after Check - Existing Lead and prepares context
// for the AI and all downstream nodes

const sheetRow = $input.item.json;

// Check if this is an existing lead (Phone field returned from sheet)
const isExistingLead = !!(sheetRow && sheetRow.Phone);

const isFreshLead = !isExistingLead;
// Spread all sheet columns through (keeps Lead_Status, Booking_Status etc for Switch)
return {
  ...sheetRow,
  existing_lead_status: sheetRow.Lead_Status || '',
  existing_booking_status: sheetRow.Booking_Status || '',
  existing_calendar_event_id: sheetRow.Calendar_Event_ID || '',
  is_existing_lead: isExistingLead,
  is_fresh_lead: isFreshLead  // ← NEW flag
};

