parameters.jsCode:
// Safely parse AI output and merge with existing lead data
const raw = $input.item.json.output || '';
let parsed;

try {
  // Strip any accidental markdown fences
  const cleaned = raw.replace(/```json|```/gi, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  // Fallback if JSON parse fails
  parsed = {
    category: 'Needs Info',
    reply: 'Sorry, I had a small issue. Could you please repeat that? 🙏',
    booking_date: null,
    booking_time: null,
    collected_data: { email: null, goal: null, experience: null, injuries: null }
  };
}

// Validate required fields
const validCategories = ['Interested', 'Booking Pending', 'Needs Info', 'Not Interested', 'Reschedule', 'Cancel Booking'];
if (!validCategories.includes(parsed.category)) {
  parsed.category = 'Needs Info';
}

// Safety check: only set Booking Pending if BOTH date and time are present
if (parsed.category === 'Booking Pending') {
  if (!parsed.booking_date || !parsed.booking_time ||
      parsed.booking_date === 'null' || parsed.booking_time === 'null') {
    parsed.category = 'Interested';
    parsed.booking_date = null;
    parsed.booking_time = null;
  }
}

// ANTI-REBOOK GUARD:
// If lead already has a confirmed booking and AI tries to create a new one,
// block it. This prevents auto-rebook when sheet data is manually edited.
const existingBookingStatus = $('Code - Prepare Context').item.json.existing_booking_status || '';
const isConfirmed = existingBookingStatus === 'Confirmed - Calendar Created' || existingBookingStatus === 'Rescheduled - Calendar Updated';
if (isConfirmed && parsed.category === 'Booking Pending') {
  parsed.category = 'Interested';
  parsed.reply = 'You already have a confirmed booking! To change it, just let me know your new preferred date and time. 📅';
}

// Safety check: Reschedule needs BOTH new date and time
if (parsed.category === 'Reschedule') {
  if (!parsed.booking_date || !parsed.booking_time ||
      parsed.booking_date === 'null' || parsed.booking_time === 'null') {
    parsed.category = 'Interested';
    parsed.booking_date = null;
    parsed.booking_time = null;
  }
}

// Build the WhatsApp-ready phone (add country code if missing)
const rawPhone = ($('Merge - All Sources').item.json.Lead_Phone || '').replace(/^=/, '');

return {
  category: parsed.category,
  reply: parsed.reply || '',
  booking_date: parsed.booking_date || null,
  booking_time: parsed.booking_time || null,
  collected_email: (parsed.collected_data && parsed.collected_data.email) ? parsed.collected_data.email : null,
  collected_goal: (parsed.collected_data && parsed.collected_data.goal) ? parsed.collected_data.goal : null,
  collected_experience: (parsed.collected_data && parsed.collected_data.experience) ? parsed.collected_data.experience : null,
  collected_injuries: (parsed.collected_data && parsed.collected_data.injuries) ? parsed.collected_data.injuries : null,
  Lead_Phone: rawPhone,
  Lead_Name: $('Merge - All Sources').item.json.Lead_Name,
  Lead_Source: $('Merge - All Sources').item.json.Lead_Source,
  whapi_to: rawPhone + '@s.whatsapp.net',
  existing_calendar_event_id: $('Code - Prepare Context').item.json.existing_calendar_event_id || ''
};

