// ── WHAPI Payload Normalizer ──────────────────────────────────────────────
// Handles all 4 real event types WHAPI sends to the same webhook URL:
//   1. Delivery receipt  → body.statuses[]   (no messages key at all)
//   2. Read receipt      → body.statuses[]   (no messages key at all)
//   3. Bot echo          → messages[0].from_me = true
//   4. Real user message → messages[0].from_me = false ✅

const body = $input.item.json.body || {};

// ── GUARD 1: Status/receipt events (statuses array, no messages) ──────────
if (body.statuses && body.statuses.length > 0) {
  return [{ json: { _skip: true, _reason: 'delivery_or_read_receipt', _status: body.statuses[0].status || 'unknown' } }];
}

// ── GUARD 2: No messages array at all (call events, group events, etc.) ───
if (!body.messages || body.messages.length === 0) {
  return [{ json: { _skip: true, _reason: 'no_messages_array' } }];
}

const msg = body.messages[0];

// ── GUARD 3: Bot echo - our own sent messages bouncing back ───────────────
if (msg.from_me === true) {
  return [{ json: { _skip: true, _reason: 'bot_echo_from_me_true' } }];
}

// ── GUARD 4: Extract text from all possible WHAPI message formats ─────────
let text = null;
let msgType = msg.type || 'unknown';

if (msg.text && msg.text.body)             text = msg.text.body;
else if (msg.caption)                      text = msg.caption;
else if (msg.image && msg.image.caption)   text = msg.image.caption;
else if (msg.video && msg.video.caption)   text = msg.video.caption;
else if (msg.document && msg.document.caption) text = msg.document.caption;
else if (msg.reaction && msg.reaction.text)    text = msg.reaction.text;
else if (msg.body && typeof msg.body === 'string') text = msg.body;

// ── GUARD 5: Non-text messages (voice notes, stickers, location, etc.) ────
if (!text) {
  // Still pass through but with a polite fallback message so user gets a reply
  text = '[Non-text message - please reply with text 🙏]';
}

// ── PASS: Normalized lead data - always the same shape downstream ─────────
const phone = (msg.from || '').replace('@s.whatsapp.net', '').replace(/\D/g, '');

return [{ json: {
  _skip: false,
  _msg_type: msgType,
  Lead_Name: msg.from_name || msg.push_name || phone || 'WhatsApp User',
  Lead_Phone: phone,
  Lead_Message: text,
  Lead_Source: 'Whatsapp'
}}];
